+.modalWindow {
+  position: relative; /* Анкор для крестика и скроллбара */
+  background: #121212;
+  border: 1px solid rgba(255, 255, 255, 0.1);
+  border-radius: 20px;
+  padding: 32px;
+  max-width: 1040px;
+  max-height: 80vh;
+  display: flex;
+  flex-direction: column;
+  overflow-y: auto;   /* Разрешаем окну вертикальный скролл */
+  
+  /* Полностью уничтожаем видимость дефолтного скролла */
+  scrollbar-width: none;
+  -ms-overflow-style: none;
+}
+
+.modalWindow::-webkit-scrollbar {
+  display: none;
+  width: 0;
+  height: 0;
+}
+
+/* Кнопка закрытия в верхнем правом углу */
+.closeButton {
+  position: absolute;
+  top: 24px;
+  right: 32px;
+  width: 24px;
+  height: 24px;
+  background: none;
+  border: none;
+  cursor: pointer;
+  padding: 0;
+  display: flex;
+  justify-content: center;
+  align-items: center;
+  z-index: 10;
+}
+
+/* Линии кастомного крестика */
+.closeLine {
+  position: relative;
+  width: 20px;
+  height: 1.5px;
+  background-color: rgba(255, 255, 255, 0.6);
+  transform: rotate(45deg);
+  transition: background-color 0.2s ease, transform 0.2s ease;
+}
+
+.closeLine::before {
+  content: "";
+  position: absolute;
+  top: 0;
+  left: 0;
+  width: 100%;
+  height: 100%;
+  background-color: inherit;
+  transform: rotate(90deg);
+}
+
+.closeButton:hover .closeLine {
+  background-color: rgba(255, 255, 255, 1);
+  transform: rotate(135deg);
+}
+
+/* Строгий центрированный заголовок-span */
+.modalTitle {
+  display: block;
+  font-size: 28px;
+  font-weight: 500;
+  line-height: 32px;
+  color: rgba(255, 255, 255, 1);
+  text-align: center;
+  margin-left: auto;
+  margin-right: auto;
+  margin-bottom: 32px;
+}
+
+/* Трехколоночная адаптивная сетка фотографий */
+.photoGrid {
+  display: flex;
+  flex-wrap: wrap;
+  gap: 40px;
+  width: 100%;
+  padding-right: 24px; /* Зазор, чтобы контент не залезал под парящий скролл */
+}
+
+/* Адаптивные квадратные фотографии */
+.modalPhoto {
+  width: calc((100% - (40px * 2)) / 3);
+  aspect-ratio: 1 / 1;
+  object-fit: cover;
+  border-radius: 12px;
+}
+
+/* Тонкая парящая нить скролла из макета */
+.customScrollTrack {
+  position: absolute;
+  top: 88px;    /* Начинается строго под заголовком */
+  right: 24px;   /* Отступ от правого края фрейма */
+  bottom: 32px;  /* Отступ от нижнего края фрейма */
+  width: 2px;
+  background: rgba(255, 255, 255, 0.1);
+  border-radius: 1px;
+  z-index: 5;
+}
+
+/* Белая пилюля-бегунок */
+.customScrollThumb {
+  position: absolute;
+  left: 50%;
+  transform: translateX(-50%);
+  width: 12px;
+  height: 24px;
+  background: #ffffff;
+  border-radius: 10px;
+  cursor: pointer;
+  box-shadow: 0 0 8px rgba(255, 255, 255, 0.3);
+}
+

